// This script normalizes the Fathom webhook payload you pasted and enriches it with timing info.
// - Adds meeting start/end in UTC and Asia/Manila (+08:00)
// - Converts webhook/created_at timestamps
// - For each transcript line, adds an absolute local RFC3339 time using recording_start_time + relative [HH:MM:SS]

/** Helpers **/
const isArr = Array.isArray;
let root = $json;
if (isArr(root)) root = root[0] || {};
const body = root.body || root;
const headers = (root.headers || {});

// --- Time helpers ---
const OFFSET_HOURS = 8; // Asia/Manila
const pad = (n) => String(n).padStart(2, "0");

function toDate(x) {
  try { return x ? new Date(x) : null; } catch { return null; }
}

function fromEpochSeconds(sec) {
  if (!sec) return null;
  const n = Number(sec);
  if (!Number.isFinite(n)) return null;
  return new Date(n * 1000);
}

function addHours(date, hours) {
  if (!date) return null;
  return new Date(date.getTime() + hours * 3600 * 1000);
}

function toRFC3339WithOffset(dateUTC, offsetHours = OFFSET_HOURS) {
  if (!dateUTC) return null;
  // Convert UTC -> local (+offset), then format with explicit +HH:MM
  const local = addHours(dateUTC, offsetHours);
  const y = local.getFullYear();
  const m = pad(local.getMonth() + 1);
  const d = pad(local.getDate());
  const hh = pad(local.getHours());
  const mm = pad(local.getMinutes());
  const ss = pad(local.getSeconds());
  const sign = offsetHours >= 0 ? "+" : "-";
  const oh = pad(Math.floor(Math.abs(offsetHours)));
  const om = pad(Math.abs(offsetHours * 60) % 60);
  return `${y}-${m}-${d}T${hh}:${mm}:${ss}${sign}${oh}:${om}`;
}

function toISOZ(date) {
  return date ? date.toISOString() : null;
}

// Parse [HH:MM:SS] into seconds
function hmsToSeconds(hms) {
  if (!hms) return null;
  const m = String(hms).match(/^(\d{1,2}):(\d{2}):(\d{2})$/);
  if (!m) return null;
  const h = Number(m[1]), mi = Number(m[2]), s = Number(m[3]);
  if ([h, mi, s].some(n => !Number.isFinite(n))) return null;
  return h * 3600 + mi * 60 + s;
}

function addSeconds(date, seconds) {
  if (!date || seconds == null) return null;
  return new Date(date.getTime() + seconds * 1000);
}

/** Core fields **/
const meetingTitle = body.meeting_title || body.title || null;
const meetingId = body.recording_id ?? null;
const meetingUrl = body.share_url || body.url || null;
const transcriptLanguage = body.transcript_language || null;

// Times from payload
const recordingStartUtc = toDate(body.recording_start_time); // ISO Z
const recordingEndUtc   = toDate(body.recording_end_time);
const createdAtUtc      = toDate(body.created_at);
const webhookTsUtc      = fromEpochSeconds(headers["webhook-timestamp"]); // seconds epoch

// Local (+08:00) strings
const meetingStartUtc = toISOZ(recordingStartUtc);
const meetingEndUtc   = toISOZ(recordingEndUtc);
const createdAtIsoUtc = toISOZ(createdAtUtc);
const webhookIsoUtc   = toISOZ(webhookTsUtc);

const meetingStartLocal = toRFC3339WithOffset(recordingStartUtc, OFFSET_HOURS);
const meetingEndLocal   = toRFC3339WithOffset(recordingEndUtc, OFFSET_HOURS);
const createdAtLocal    = toRFC3339WithOffset(createdAtUtc, OFFSET_HOURS);
const webhookLocal      = toRFC3339WithOffset(webhookTsUtc, OFFSET_HOURS);

// Invitees
const invitees = (body.calendar_invitees || []).map(i => ({
  name: i.name || i.matched_speaker_display_name || "Unknown",
  email: i.email || "N/A",
}));

// Transcript with absolute local times (if recordingStartUtc + [HH:MM:SS] available)
const transcriptLines = (body.transcript || []).map(t => {
  const speaker = (t.speaker && t.speaker.display_name) || "Unknown";
  const rel = t.timestamp || null; // HH:MM:SS
  let absLocal = null;

  if (recordingStartUtc && rel) {
    const sec = hmsToSeconds(rel);
    if (sec != null) {
      const absUtc = addSeconds(recordingStartUtc, sec);
      absLocal = toRFC3339WithOffset(absUtc, OFFSET_HOURS);
    }
  }

  const tsRel = rel ? `[${rel}]` : "";
  const tsAbs = absLocal ? `[${absLocal}]` : "";
  // Include both relative and absolute if available
  return `${tsRel}${tsAbs} ${speaker}: ${t.text}`;
});

// Summary
const summary = (body.default_summary && body.default_summary.markdown_formatted) || null;

/** Output **/
return {
  meetingId,
  meetingTitle,
  invitees,
  transcriptLanguage,
  summary,
  transcript: transcriptLines.join("\n"),
  meetingUrl,

  // Extra timing context
  timing: {
    timezone: "Asia/Manila (+08:00)",
    meetingStartUtc,
    meetingEndUtc,
    meetingStartLocal,
    meetingEndLocal,
    createdAtUtc: createdAtIsoUtc,
    createdAtLocal,
    webhookTimestampUtc: webhookIsoUtc,
    webhookTimestampLocal: webhookLocal,
  },
};

