const meetingStartLocal = toRFC3339WithOffset(recordingStartUtc, OFFSET_HOURS);
const meetingEndLocal   = toRFC3339WithOffset(recordingEndUtc, OFFSET_HOURS);
const createdAtLocal    = toRFC3339WithOffset(createdAtUtc, OFFSET_HOURS);
const webhookLocal      = toRFC3339WithOffset(webhookTsUtc, OFFSET_HOURS);

// Invitees
const invitees = (body.calendar_invitees || []).map(i => ({
  name: i.name || i.matched_speaker_display_name || "Unknown",
  email: i.email || "N/A",
}));

// Transcript with absolute local times (if recordingStartUtc + [HH:MM:SS] available)
const transcriptLines = (body.transcript || []).map(t => {
  const speaker = (t.speaker && t.speaker.display_name) || "Unknown";
  const rel = t.timestamp || null; // HH:MM:SS
  let absLocal = null;

  if (recordingStartUtc && rel) {
    const sec = hmsToSeconds(rel);
    if (sec != null) {
      const absUtc = addSeconds(recordingStartUtc, sec);
      absLocal = toRFC3339WithOffset(absUtc, OFFSET_HOURS);
    }
  }

  const tsRel = rel ? `[${rel}]` : "";
  const tsAbs = absLocal ? `[${absLocal}]` : "";
  // Include both relative and absolute if available
  return `${tsRel}${tsAbs} ${speaker}: ${t.text}`;
});

// Summary
const summary = (body.default_summary && body.default_summary.markdown_formatted) || null;

/** Output **/
return {
  meetingId,
  meetingTitle,
  invitees,
  transcriptLanguage,
  summary,
  transcript: transcriptLines.join("\n"),
  meetingUrl,

  // Extra timing context
  timing: {
    timezone: "Asia/Manila (+08:00)",
    meetingStartUtc,
    meetingEndUtc,
    meetingStartLocal,
    meetingEndLocal,
    createdAtUtc: createdAtIsoUtc,
    createdAtLocal,
    webhookTimestampUtc: webhookIsoUtc,
    webhookTimestampLocal: webhookLocal,
  },
};

