// This Function node expects the AI Agent's result in item.json.output
// Node type MUST be "Function" (not "Function Item")

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&quot;')
    .replace(/'/g, '&#39;');
}

const newItems = [];

for (const item of items) {
  let data;

  // 1) Get the agent output
  let raw = item.json.output;

  if (raw && typeof raw === 'object') {
    // already parsed
    data = raw;
  } else if (typeof raw === 'string') {
    raw = raw.trim();

    // strip ```json fences if present
    if (raw.startsWith('```')) {
      raw = raw.replace(/^```[a-zA-Z]*\s*/m, '');
      raw = raw.replace(/```[\s]*$/m, '');
      raw = raw.trim();
    }

    if (!raw) {
      newItems.push(item);
      continue;
    }

    try {
      data = JSON.parse(raw);
    } catch (err) {
      newItems.push({
        json: {
          ...item.json,
          _parseError: 'Failed to parse AI output as JSON',
          _rawOutput: raw,
          _errorMessage: err.message,
        },
      });
      continue;
    }
  } else {
    // no usable output
    newItems.push(item);
    continue;
  }

  // 2) Pull pieces out (INTERNAL MEETING SCHEMA)
  const meta     = data.meta || {};
  const sections = data.sections || {};
  const email    = data.email || {};

  const tasks      = Array.isArray(sections.tasks) ? sections.tasks : [];
  const challenges = Array.isArray(sections.challenges) ? sections.challenges : [];
  const others     = sections.others || {};

  const bodyText = email.body || '';

  // 3) Subject: keep AI subject if present, otherwise build a sensible internal summary
  const clientName   = meta.clientName || meta.client || '';
  const meetingTitle = meta.meetingTitle || '';
  let subjectOut     = email.subject || '';

  if (!subjectOut && (clientName || meetingTitle)) {
    const clientLabel = clientName || 'Team';
    const titleLabel  = meetingTitle || 'Internal Meeting';
    subjectOut = `Internal Meeting Summary - ${clientLabel} - ${titleLabel}`;
  }

  // 4) Intro paragraphs from plain-text body (no headings expected)
  const lines = String(bodyText || '').split('\n');
  const paragraphs = [];
  let buffer = [];

  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) {
      if (buffer.length) {
        paragraphs.push(buffer.join(' '));
        buffer = [];
      }
    } else {
      buffer.push(trimmed);
    }
  }
  if (buffer.length) {
    paragraphs.push(buffer.join(' '));
  }

  const introParts = paragraphs.map(p =>
    `<p style="margin:0 0 16px 0; font-size:14px; line-height:20px;">${escapeHtml(p)}</p>`
  );

  // 5) Tasks table (core action items)
  let tasksSection = '';
  const realTasks = tasks.filter(t => {
    const title = (t.title || '').trim().toLowerCase();
    const desc  = (t.description || '').trim().toLowerCase();
    if (!title && !desc) return false;
    if (title === 'none discussed.' || desc === 'none discussed.') return false;
    return true;
  });

  if (realTasks.length > 0) {
    tasksSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">Action Items</h3>
        <table border="1" cellpadding="6" cellspacing="0"
               style="border-collapse:collapse; width:100%; border:1px solid #e5e7eb; table-layout:fixed; font-size:14px;line-height:20px;">
          <colgroup>
            <col style="width:35%;">  <!-- Task -->
            <col style="width:15%;">  <!-- Owner -->
            <col style="width:15%;">  <!-- Status -->
            <col style="width:15%;">  <!-- Due Date -->
            <col style="width:20%;">  <!-- Challenges -->
          </colgroup>
          <thead>
            <tr style="background:#f9fafb;">
              <th style="text-align:center;font-size:14px;line-height:20px;">Task</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Owner</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Status</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Due Date</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Challenges</th>
            </tr>
          </thead>
          <tbody>
            ${realTasks.map(t => {
              const title = (t.title || '').trim() || 'Untitled task';
              const desc  = (t.description || '').trim();
              const owner = t.owner || 'TBD';
              const status = t.status || 'TBD';
              const dueDate = t.due_date || 'TBD';

              const relChallengesRaw = Array.isArray(t.related_challenges) ? t.related_challenges : [];
              const relChallenges = relChallengesRaw
                .map(c => String(c || '').trim())
                .filter(c => c.length > 0);

              const challengesHtml = relChallenges.length
                ? `<div style="margin:0;font-size:13px;line-height:18px;">
                     ${relChallenges.map(c => escapeHtml(c)).join('<br />')}
                   </div>`
                : `<span style="font-size:13px;line-height:18px;color:#9ca3af;">—</span>`;

              const descHtml = desc
                ? `<div style="margin-top:4px;font-size:14px;line-height:20px;color:#4b5563;">
                     ${escapeHtml(desc)}
                   </div>`
                : '';

              return `
                <tr>
                  <td style="vertical-align:top;font-size:14px;line-height:20px;">
                    <strong>${escapeHtml(title)}</strong>
                    ${descHtml}
                  </td>
                  <td style="vertical-align:top; text-align:center;font-size:14px;line-height:20px;">${escapeHtml(owner)}</td>
                  <td style="vertical-align:top; text-align:center;font-size:14px;line-height:20px;">${escapeHtml(status)}</td>
                  <td style="vertical-align:top; text-align:center;font-size:14px;line-height:20px;">${escapeHtml(dueDate)}</td>
                  <td style="vertical-align:top; text-align:left;font-size:14px;line-height:20px;">
                    ${challengesHtml}
                  </td>
                </tr>
              `;
            }).join('')}
          </tbody>
        </table>
      </div>
    `;
  }

  // 6) Challenges list (overall issues / blockers)
  let challengesSection = '';
  const realChallenges = challenges.filter(ch => {
    const summary = (ch.summary || '').trim().toLowerCase();
    const details = (ch.details || '').trim().toLowerCase();
    if (!summary && !details) return false;
    if (summary === 'none discussed.' || details === 'none discussed.') return false;
    return true;
  });

  if (realChallenges.length > 0) {
    const listItems = realChallenges.map(ch => {
      const summary = ch.summary || '';
      const details = ch.details || '';
      const owner   = ch.owner || 'TBD';
      const related = ch.related_task || '';

      const metaBits = [];
      if (owner && owner !== 'TBD') metaBits.push(`Owner: ${owner}`);
      if (related && related !== 'TBD') metaBits.push(`Related task: ${related}`);
      // timestamp intentionally NOT shown in the email anymore

      const metaText = metaBits.length
        ? `<div style="margin-top:2px;font-size:12px;line-height:16px;color:#6b7280;">${escapeHtml(metaBits.join(' • '))}</div>`
        : '';

      return `
        <li style="margin-bottom:8px;font-size:14px;line-height:20px;">
          <strong>${escapeHtml(summary)}</strong>
          ${details ? ` – ${escapeHtml(details)}` : ''}
          ${metaText}
        </li>
      `;
    });

    challengesSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">Challenges &amp; Blockers</h3>
        <ul style="margin:0 0 10px 20px; padding:0 0 0 18px; list-style-type:disc;">
          ${listItems.join('')}
        </ul>
      </div>
    `;
  }


  // 7) Others (notes, logistics, unresolved questions)
  let othersSection = '';

  const notes = Array.isArray(others.notes) ? others.notes : [];
  const logistics = Array.isArray(others.logistics) ? others.logistics : [];
  const unresolved = Array.isArray(others.unresolved_questions) ? others.unresolved_questions : [];

  function hasRealContent(arr) {
    if (!arr || arr.length === 0) return false;
    if (arr.length === 1 && typeof arr[0] === 'string' &&
        arr[0].trim().toLowerCase() === 'none discussed.') {
      return false;
    }
    return true;
  }

  const hasNotes      = hasRealContent(notes);
  const hasLogistics  = hasRealContent(logistics);
  const hasUnresolved = hasRealContent(unresolved);

  if (hasNotes || hasLogistics || hasUnresolved) {
    const notesHtml = hasNotes
      ? `
        <p style="margin:8px 0 4px 0;font-size:14px;line-height:20px;"><strong>Notes</strong></p>
        <ul style="margin:0 0 10px 20px; padding:0 0 0 18px; list-style-type:disc;">
          ${notes.map(n => `<li style="font-size:14px;line-height:20px;">${escapeHtml(n)}</li>`).join('')}
        </ul>
      `
      : '';

    const logisticsHtml = hasLogistics
      ? `
        <p style="margin:8px 0 4px 0;font-size:14px;line-height:20px;"><strong>Logistics</strong></p>
        <ul style="margin:0 0 10px 20px; padding:0 0 0 18px; list-style-type:disc;">
          ${logistics.map(l => `<li style="font-size:14px;line-height:20px;">${escapeHtml(l)}</li>`).join('')}
        </ul>
      `
      : '';

    const unresolvedHtml = hasUnresolved
      ? `
        <p style="margin:8px 0 4px 0;font-size:14px;line-height:20px;"><strong>Unresolved Questions</strong></p>
        <ul style="margin:0 0 10px 20px; padding:0 0 0 18px; list-style-type:disc;">
          ${unresolved.map(q => `<li style="font-size:14px;line-height:20px;">${escapeHtml(q)}</li>`).join('')}
        </ul>
      `
      : '';

    othersSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">Additional Notes &amp; Logistics</h3>
        ${notesHtml}
        ${logisticsHtml}
        ${unresolvedHtml}
      </div>
    `;
  }

  // 8) Custom closing + signoff (HTML only, not in plain-text body)
  const customClosing = `<p style="margin:16px 0 12px 0; font-size:14px; line-height:20px;">If there is anything I missed or if you would like to adjust any of the tasks or priorities, please feel free to let me know.</p>`;

  const signName = 'Scale Virtually Team';
  const signoffHtml = [
    `<p style="margin:0 0 12px 0; font-size:14px; line-height:20px;">Best regards,</p>`,
    `<p style="margin:0 0 12px 0; font-size:14px; line-height:20px;">${escapeHtml(signName)}</p>`
  ].join('\n');

  // 9) Combine all sections into main content
  const detailSections = [
    tasksSection,
    challengesSection,
    othersSection,
  ].filter(Boolean).join('\n');

  let finalHtml = '';

  if (introParts.length) {
    finalHtml += introParts.join('\n');
  }

  if (detailSections) {
    finalHtml += '\n' + detailSections;
  }

  finalHtml += '\n' + customClosing;
  finalHtml += '\n' + signoffHtml;

  // 10) Wrap in card layout with wider header (900px)
  const safeMeetingTitle = meetingTitle || 'Internal Meeting';

  const headerBlock = `
    <table role="presentation" cellpadding="0" cellspacing="0" width="100%">
      <tr>
        <td align="center" style="padding:24px;">
          <table role="presentation" cellpadding="0" cellspacing="0" width="900" style="max-width:900px;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #e5e7eb;">
            <tr>
              <td style="background:#ea7b21;color:#ffffff;padding:20px 28px;border-radius:12px 12px 0 0;text-align:center;">
                <h1 style="margin:0 0 4px 0;font-size:22px;line-height:28px;font-weight:700;font-family:Arial,Helvetica,sans-serif;">
                  Internal Meeting Minutes
                </h1>
                <p style="margin:0;font-size:13px;line-height:18px;font-family:Arial,Helvetica,sans-serif;">
                  ${escapeHtml(safeMeetingTitle)}
                </p>
              </td>
            </tr>
            <tr>
              <td style="padding:24px 28px 28px 28px;background:#ffffff;font-size:14px;line-height:20px;">
                ${finalHtml.trim()}
              </td>
            </tr>
          </table>
        </td>
      </tr>
    </table>
  `.trim();

  const fullHtml = `
<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <title>${escapeHtml(subjectOut || '')}</title>
  </head>
  <body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,Helvetica,sans-serif;color:#111827;">
    ${headerBlock}
  </body>
</html>
  `.trim();

  // 11) Push final structured item
  newItems.push({
    json: {
      meta,
      sections,
      email: {
        subject: subjectOut || '',
        body_text: bodyText,
        body_html: fullHtml,
      },
      raw: data,
    },
  });
}

return newItems;

const item = $input.first().json;
const meta = item.meta ?? {};
const sections = item.sections ?? {};
const email = item.email ?? {};
const raw = item.raw ?? {};
const transcript = $items('Transcript Cleaner', 0, 0)[0]?.json ?? {};
const timing = transcript.timing ?? {};
const occurredAt = timing.meetingStartUtc || timing.createdAtUtc || new Date().toISOString();
const meetingId = meta.meetingId ?? null;
const meetingUrl = meta.meetingUrl || transcript.meetingUrl || null;

return [{
  json: {
    source_id: null,
    journal_date: String(occurredAt).slice(0, 10),
    occurred_at: occurredAt,
    entry_type: 'meeting_note',
    importance: 'normal',
    actor_name: null,
    project_id: null,
    project_name: meta.clientName ?? null,
    team_name: 'Solution Architects',
    title: email.subject || meta.meetingTitle || 'Internal Meeting Summary',
    summary: email.body_text || 'Internal meeting summary generated from Fathom transcript.',
    details: {
      source_type: 'fathom_mom',
      external_source_id: meetingId,
      meeting_title: meta.meetingTitle ?? null,
      meeting_url: meetingUrl,
      invitees: meta.invitees ?? [],
      sections,
      raw,
      transcript_source: transcript
    },
    links: {
      source_url: meetingUrl,
      unique_key: meetingId ? ('fathom_mom_' + meetingId) : null
    }
  }
}];
